#include <stdio.h>
#include <stdlib.h>
#include <string.h>

char* encode(char** strs, int strsSize) {
    int len = 0;
    for (int i = 0; i < strsSize; i++) {
        len += strlen(strs[i]) + 4;
    }
    char* res = (char*)malloc(len * sizeof(char));
    char* p = res;
    for (int i = 0; i < strsSize; i++) {
        sprintf(p, "%d#", strlen(strs[i]));
        p += strlen(p);
        strcpy(p, strs[i]);
        p += strlen(strs[i]);
    }
    return res;
}

char** decode(char* s, int* returnSize) {
    int len = strlen(s);
    char** res = (char**)malloc(len * sizeof(char*));
    *returnSize = 0;
    char* p = s;
    while (p < s + len) {
        int l = atoi(p);
        p += strlen(p) + 1;
        res[(*returnSize)++] = (char*)malloc((l + 1) * sizeof(char));
        strncpy(res[(*returnSize) - 1], p, l);
        res[(*returnSize) - 1][l] = '\0';
        p += l;
    }
    return res;
}

code.C++:
#include <iostream>
#include <vector>
#include <string>

std::string encode(std::vector<std::string>& strs) {
    std::string res;
    for (const auto& s : strs) {
        res += std::to_string(s.size()) + "#" + s;
    }
    return res;
}

std::vector<std::string> decode(std::string s) {
    std::vector<std::string> res;
    int i = 0;
    while (i < s.size()) {
        int j = s.find('#', i);
        int len = std::stoi(s.substr(i, j - i));
        i = j + 1;
        res.push_back(s.substr(i, len));
        i += len;
    }
    return res;
}

code.Java:
public class Solution {
    public String encode(String[] strs) {
        StringBuilder sb = new StringBuilder();
        for (String s : strs) {
            sb.append(s.length()).append("#").append(s);
        }
        return sb.toString();
    }

    public String[] decode(String s) {
        String[] res = new String[s.length()];
        int i = 0;
        int idx = 0;
        while (i < s.length()) {
            int j = s.indexOf('#', i);
            int len = Integer.parseInt(s.substring(i, j));
            i = j + 1;
            res[idx++] = s.substring(i, i + len);
            i += len;
        }
        return res;
    }
}

